import java.util.Scanner;

public class SecureBuffer {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.println("Enter a string: ");
        String input = scanner.nextLine();

        int maxLength = Math.min(input.length(), 10); // Limit input length to size of buffer
        char[] buffer = new char[10];

        // Copy at most 10 characters from input to buffer
        input.getChars(0, maxLength, buffer, 0);

        System.out.println("Buffer contents: " + new String(buffer));
    }
}

### Explanation:
취약유형: Buffer Overflow
